hitMacro.command:
const STATUSES = ["berserk","charmed","confused","frightened"];
const tgts = (typeof targets !== "undefined" && targets?.length)
  ? targets
  : Array.from(game.user.targets);
if (!tgts.length) return ui.notifications.warn("No token targeted.");

for (const t of tgts) {
  for (const s of STATUSES) {
    if (t.actor.statuses.has(s)) await t.actor.toggleStatusEffect(s, { active: false });
  }
}

//ui.notifications.info(`Hymn: cleared statuses on ${tgts.length} target(s).`);
